import{_ as o,o as t,c as i,a2 as c}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"Epic: Infrastructure","description":"","frontmatter":{},"headers":[],"relativePath":"epics/infrastructure.md","filePath":"epics/infrastructure.md"}'),s={name:"epics/infrastructure.md"};function d(r,e,a,n,l,p){return t(),i("div",null,[...e[0]||(e[0]=[c('<h1 id="epic-infrastructure" tabindex="-1">Epic: Infrastructure <a class="header-anchor" href="#epic-infrastructure" aria-label="Permalink to &quot;Epic: Infrastructure&quot;">​</a></h1><blockquote><p>Monorepo scaffold, shared packages, Docker (dev + prod), CI pipeline, testing infrastructure, and non-Docker deployment paths.</p></blockquote><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>⏳ In Progress</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Infrastructure covers the foundation that everything else runs on: the Turborepo + pnpm monorepo, shared TypeScript configs, the database package, Docker Compose for dev and production, the GitHub Actions CI pipeline, the E2E test suite, and non-Docker deployment (PM2 in v0.5, systemd planned). The only pending item is epic task 0.13 (systemd), which adds a zero-extra-dependency Linux production path alongside PM2.</p><h2 id="tasks" tabindex="-1">Tasks <a class="header-anchor" href="#tasks" aria-label="Permalink to &quot;Tasks&quot;">​</a></h2><h4 id="✅-0-1-—-monorepo-scaffold" tabindex="-1">✅ 0.1 — Monorepo scaffold <a class="header-anchor" href="#✅-0-1-—-monorepo-scaffold" aria-label="Permalink to &quot;✅ 0.1 — Monorepo scaffold&quot;">​</a></h4><p><strong>Goal:</strong> Bare monorepo structure with pnpm workspaces and Turborepo configured. No application code.</p><p><strong>Deliverables:</strong></p><ul><li>Root <code>package.json</code> with pnpm workspace config</li><li><code>pnpm-workspace.yaml</code> declaring <code>apps/*</code>, <code>packages/*</code>, <code>plugins/*</code>, <code>runtime</code></li><li><code>turbo.json</code> with basic pipeline: <code>build</code>, <code>dev</code>, <code>lint</code>, <code>typecheck</code></li><li>Empty directories: <code>apps/</code>, <code>packages/</code>, <code>plugins/</code>, <code>runtime/</code>, <code>scripts/</code>, <code>bin/</code>, <code>docs/</code>, <code>data/</code></li><li><code>scripts/install-plugins.ts</code> — stub only: reads a <code>sovereign.plugins.json</code> config file at repo root, logs &quot;not yet implemented&quot;. Full implementation in Task 0.5.00.</li><li>Root <code>.gitignore</code> covering <code>node_modules</code>, <code>dist</code>, <code>.next</code>, <code>data/*.db</code>, <code>runtime/app/plugins/</code></li><li>Root <code>README.md</code> — one paragraph, links to SRS doc</li></ul><p><strong>SRS reference:</strong> 2.3 Monorepo Structure, 2.2 Tech Stack</p><p><strong>Review checklist:</strong></p><ul><li><code>pnpm install</code> runs without errors</li><li><code>turbo build</code> runs without errors (no-ops since no packages exist yet)</li><li>Directory structure matches SRS 2.3 exactly</li></ul><hr><h4 id="✅-0-2-—-shared-typescript-config" tabindex="-1">✅ 0.2 — Shared TypeScript config <a class="header-anchor" href="#✅-0-2-—-shared-typescript-config" aria-label="Permalink to &quot;✅ 0.2 — Shared TypeScript config&quot;">​</a></h4><p><strong>Goal:</strong> Centralised TypeScript configuration inherited by all packages and apps.</p><p><strong>Deliverables:</strong></p><ul><li><code>packages/tsconfig/</code> package with: <ul><li><code>base.json</code> — strict mode, path aliases, target ES2022</li><li><code>nextjs.json</code> — extends base, Next.js specific settings</li><li><code>library.json</code> — extends base, for non-Next packages</li></ul></li><li>Each future package/app will extend one of these</li></ul><p><strong>SRS reference:</strong> 2.2 Tech Stack</p><p><strong>Review checklist:</strong></p><ul><li><code>packages/tsconfig/package.json</code> correctly exports all three configs</li><li>Configs are strict — <code>strict: true</code>, <code>noUncheckedIndexedAccess: true</code></li></ul><hr><h4 id="✅-0-3-—-code-quality-tooling" tabindex="-1">✅ 0.3 — Code quality tooling <a class="header-anchor" href="#✅-0-3-—-code-quality-tooling" aria-label="Permalink to &quot;✅ 0.3 — Code quality tooling&quot;">​</a></h4><p><strong>Goal:</strong> Establish consistent code formatting and linting across the entire monorepo before any application code is written. All subsequent tasks inherit this baseline — nothing is merged without passing it.</p><p><strong>Deliverables:</strong></p><ul><li><code>.editorconfig</code> at repo root — indent style (spaces, 2), line endings (LF), charset (UTF-8), trailing newline, trim trailing whitespace</li><li><code>prettier.config.ts</code> at repo root — single quotes, semicolons, trailing commas (<code>all</code>), print width 100, tab width 2</li><li><code>eslint.config.ts</code> at repo root — ESLint 9 flat config: <ul><li><code>typescript-eslint</code> recommended + strict rules</li><li><code>eslint-config-prettier</code> to disable formatting rules that conflict with Prettier</li><li><code>no-restricted-imports</code> rule scoped to <code>plugins/**</code> — blocks any import matching <code>*/runtime/src/*</code>. This is the SDK boundary rule (NFR-06); wiring it here means it is active from the first line of plugin code, not retroactively added in the SDK task</li></ul></li><li><code>package.json</code> additions: <ul><li><code>simple-git-hooks</code> — pre-commit hook running lint-staged</li><li><code>lint-staged</code> — runs <code>prettier --write</code> then <code>eslint --fix</code> on staged <code>.ts</code>/<code>.tsx</code>/<code>.css</code>/<code>.json</code> files</li><li>Scripts: <code>&quot;format&quot;: &quot;prettier --write .&quot;</code>, <code>&quot;format:check&quot;: &quot;prettier --check .&quot;</code>, <code>&quot;lint:fix&quot;: &quot;eslint --fix .&quot;</code></li></ul></li><li><code>turbo.json</code> — confirm <code>lint</code> task is correctly wired across packages</li><li>Run <code>pnpm format</code> on all existing files (<code>.gitignore</code>, <code>README.md</code>, <code>package.json</code>, <code>pnpm-workspace.yaml</code>, <code>turbo.json</code>, <code>scripts/install-plugins.ts</code>) and commit formatted output as part of this PR</li></ul><p><strong>Technology:</strong> ESLint 9 (flat config) + <code>typescript-eslint</code> + Prettier + <code>eslint-config-prettier</code> + <code>simple-git-hooks</code> + <code>lint-staged</code>. See CLAUDE.md — Code quality section. No Biome — ESLint is required for the custom <code>no-restricted-imports</code> SDK boundary rule; running both would be redundant.</p><p><strong>SRS reference:</strong> NFR-06, PLT-10, SRS §2.2 Tech Stack</p><p><strong>Review checklist:</strong></p><ul><li><code>pnpm format:check</code> passes on all files in the repo</li><li><code>pnpm lint</code> passes with zero errors or warnings</li><li>Attempting to commit a file with formatting errors is blocked by the pre-commit hook</li><li>A test import of <code>runtime/src/anything</code> inside <code>plugins/</code> causes ESLint to error — boundary rule is live</li></ul><hr><h4 id="✅-0-4-—-packages-db-—-drizzle-client-factory" tabindex="-1">✅ 0.4 — <code>packages/db</code> — Drizzle client factory <a class="header-anchor" href="#✅-0-4-—-packages-db-—-drizzle-client-factory" aria-label="Permalink to &quot;✅ 0.4 — `packages/db` — Drizzle client factory&quot;">​</a></h4><p><strong>Goal:</strong> Shared database package providing a Drizzle client factory that supports both SQLite and PostgreSQL via a dialect flag.</p><p><strong>Deliverables:</strong></p><ul><li><code>packages/db/</code> with: <ul><li><code>src/client.ts</code> — exports <code>createClient(config)</code> returning a Drizzle instance</li><li><code>src/dialect.ts</code> — reads <code>DATABASE_URL</code> and <code>DB_DIALECT</code> env vars, returns correct dialect</li><li><code>src/migrate.ts</code> — migration runner stub (accepts migration file paths, runs in order)</li><li><code>src/schema/platform.ts</code> — platform tables: <code>tenants</code>, <code>users</code>, <code>sessions</code> with <code>tenant_id</code> on users</li><li><code>src/index.ts</code> — barrel export</li></ul></li><li><code>packages/db/package.json</code> with correct dependencies: <code>drizzle-orm</code>, <code>better-sqlite3</code>, <code>pg</code></li><li><code>tsup.config.ts</code> — <code>entry: [&#39;src/index.ts&#39;]</code>, <code>format: [&#39;esm&#39;]</code>, <code>dts: true</code>, <code>clean: true</code></li><li><code>package.json</code>: <ul><li><code>build</code> script: <code>tsup</code></li><li>No <code>dev</code> script — <code>transpilePackages</code> in the consuming Next.js apps compiles this package&#39;s TypeScript source directly during dev; no watch build needed</li><li><code>exports</code> field points to TypeScript source for workspace consumption: <code>{ &quot;.&quot;: &quot;./src/index.ts&quot; }</code>. tsup overwrites this with <code>dist/</code> paths at build time for production/npm.</li></ul></li></ul><p><strong>SRS reference:</strong> 3.7 Database Layer, 3.1 Deployment Model (tenant_id)</p><p><strong>Review checklist:</strong></p><ul><li><code>createClient()</code> returns a working Drizzle instance for SQLite when <code>DB_DIALECT=sqlite</code></li><li><code>tenant_id</code> present on <code>users</code> table</li><li>Migration runner accepts an array of migration paths and runs them in order</li><li>No direct database calls — only the factory and schema definitions</li></ul><hr><h4 id="✅-0-5-—-packages-mailer-—-smtp-abstraction" tabindex="-1">✅ 0.5 — <code>packages/mailer</code> — SMTP abstraction <a class="header-anchor" href="#✅-0-5-—-packages-mailer-—-smtp-abstraction" aria-label="Permalink to &quot;✅ 0.5 — `packages/mailer` — SMTP abstraction&quot;">​</a></h4><p><strong>Goal:</strong> Thin mailer package wrapping nodemailer with a simple <code>send()</code> interface.</p><p><strong>Deliverables:</strong></p><ul><li><code>packages/mailer/</code> with: <ul><li><code>src/mailer.ts</code> — <code>createMailer(config)</code> factory, <code>send(options: MailOptions)</code> method</li><li><code>src/types.ts</code> — <code>MailOptions</code>, <code>MailerConfig</code> interfaces</li><li><code>src/index.ts</code> — barrel export</li></ul></li><li>Config reads from env: <code>SMTP_HOST</code>, <code>SMTP_PORT</code>, <code>SMTP_USER</code>, <code>SMTP_PASS</code>, <code>SMTP_FROM</code></li><li>Graceful no-op when SMTP is not configured (logs warning, does not throw)</li><li><code>tsup.config.ts</code> — <code>entry: [&#39;src/index.ts&#39;]</code>, <code>format: [&#39;esm&#39;]</code>, <code>dts: true</code>, <code>clean: true</code></li><li><code>package.json</code>: <ul><li><code>build</code> script: <code>tsup</code></li><li>No <code>dev</code> script — compiled by consuming apps via <code>transpilePackages</code></li><li><code>exports</code>: <code>{ &quot;.&quot;: &quot;./src/index.ts&quot; }</code> for workspace; overwritten at publish</li></ul></li><li><strong>Dev email capture (Mailpit):</strong> ships alongside the package so email flows are testable from day one (SRS decision log, June 2026): <ul><li><code>docker-compose.yml</code> — a <code>mailpit</code> service (SMTP <code>1025</code>, web inbox <code>8025</code>) for Docker-based dev. Task 0.3.12 adds the <code>runtime</code>/<code>auth</code> services to this same file once they exist.</li><li><code>.env.example</code> — DB + SMTP vars with Mailpit-aware comments (Docker host <code>mailpit</code>, native host <code>localhost</code>, or unset to disable email).</li><li><code>CONTRIBUTING.md</code> — an &quot;Email in development&quot; section covering the Docker service, the native <code>mailpit</code> binary, and the Ethereal no-install fallback.</li></ul></li></ul><p><strong>SRS reference:</strong> NFR-02 (email optional), SDK surface <code>sdk.mailer.send()</code>, decision log (dev email capture)</p><p><strong>Review checklist:</strong></p><ul><li><code>send()</code> accepts <code>to</code>, <code>subject</code>, <code>html</code>, <code>text</code></li><li>No-op behaviour when SMTP unconfigured — does not crash the runtime</li><li>No hardcoded credentials anywhere</li></ul><hr><h4 id="✅-0-6-—-docker-compose-for-local-dev" tabindex="-1">✅ 0.6 — Docker Compose for local dev <a class="header-anchor" href="#✅-0-6-—-docker-compose-for-local-dev" aria-label="Permalink to &quot;✅ 0.6 — Docker Compose for local dev&quot;">​</a></h4><p><strong>Goal:</strong> Docker Compose setup orchestrating runtime and auth server for local development.</p><p><strong>Deliverables:</strong></p><ul><li><code>docker-compose.yml</code> — extend the existing dev file (which already carries the <code>mailpit</code> service from Task 0.3.06) with two app services on the shared network: <ul><li><code>runtime</code> — host-mapped <code>${RUNTIME_PORT:-3000}:3000</code></li><li><code>auth</code> — internal only; <code>expose: [&quot;3001&quot;]</code>, no host <code>ports</code> mapping. The runtime reaches it at <code>http://auth:3001</code> via <code>SOVEREIGN_AUTH_URL</code>.</li></ul></li><li><code>docker-compose.prod.yml</code> — production overrides: runtime host port defaults to <code>${RUNTIME_PORT:-4000}:3000</code>; auth remains internal-only; both services get <code>restart: unless-stopped</code>. (Mailpit is dev-only — not in the prod file.)</li><li><code>.env.example</code> — extend the existing file (DB + SMTP from Task 0.3.06) with the remaining required vars: <code>RUNTIME_PORT</code>, <code>AUTH_PORT</code>, <code>SOVEREIGN_AUTH_URL</code>, <code>AUTH_SECRET</code>, <code>SOVEREIGN_AUTH_SECRET</code>, etc.</li><li><code>docs/self-hosting.md</code> — getting started guide: clone, configure env, <code>docker compose up</code></li></ul><p><strong>SRS reference:</strong> NFR-01, 2.4 Phased Roadmap v0.3, 3.1 Deployment Model (topology, ports)</p><p><strong>Review checklist:</strong></p><ul><li><code>docker compose up</code> starts both services without errors</li><li>Runtime is reachable at <code>localhost:3000</code> (dev)</li><li>Auth server is <strong>not</strong> reachable from the host — only from the runtime container on the internal network</li><li><code>.env.example</code> covers every env var used across all packages</li></ul><hr><h4 id="✅-0-7-—-production-docker-image" tabindex="-1">✅ 0.7 — Production Docker image <a class="header-anchor" href="#✅-0-7-—-production-docker-image" aria-label="Permalink to &quot;✅ 0.7 — Production Docker image&quot;">​</a></h4><p><strong>Goal:</strong> Separate production Docker images for runtime and auth, each built from Next.js standalone output.</p><p><strong>Deliverables:</strong></p><ul><li><code>Dockerfile</code> (runtime) — three-stage: <ul><li><code>deps</code> — <code>node:&lt;pinned&gt;-alpine</code> + corepack pnpm; install with <code>--frozen-lockfile</code></li><li><code>builder</code> — copy source; <code>NODE_ENV=production</code>; run <code>pnpm generate</code> (copies plugins, not symlinks) then <code>pnpm build</code> (tsup packages → next build, producing <code>.next/standalone</code>)</li><li><code>runner</code> — minimal image, non-root user, <code>NODE_ENV=production</code>; copy only <code>.next/standalone</code> + <code>.next/static</code> + <code>public</code>; <code>EXPOSE 3000</code>; <code>HEALTHCHECK</code> hitting the runtime health endpoint; <code>CMD [&quot;node&quot;, &quot;server.js&quot;]</code></li></ul></li><li><code>apps/auth/Dockerfile</code> — same three-stage pattern for the auth server; <code>EXPOSE 3001</code>; auth-specific healthcheck</li><li>Both apps set <code>output: &#39;standalone&#39;</code> in their <code>next.config.ts</code> (prerequisite)</li><li><code>docker-compose.prod.yml</code> updated to build/use these images; runtime host-mapped (default 4000), auth internal-only, both <code>restart: unless-stopped</code></li><li>No secrets baked into images — all config injected at runtime via env</li></ul><p><strong>SRS reference:</strong> NFR-01, 2.4 Phased Roadmap v0.5, 3.1 Deployment Model</p><p><strong>Review checklist:</strong></p><ul><li>Images build without errors</li><li>Each image is reasonably small (standalone output keeps them lean; target &lt; 250MB per image)</li><li>Login → session cookie → authenticated request works end-to-end across the two production containers (runtime → auth over the internal network)</li><li>Auth container is not reachable from the host</li><li>No dev dependencies and no secrets in the production images</li></ul><hr><h4 id="✅-0-8-—-postgres-validation" tabindex="-1">✅ 0.8 — Postgres validation <a class="header-anchor" href="#✅-0-8-—-postgres-validation" aria-label="Permalink to &quot;✅ 0.8 — Postgres validation&quot;">​</a></h4><p><strong>Goal:</strong> Confirm full parity between SQLite and Postgres deployments.</p><p><strong>Deliverables:</strong></p><ul><li><code>docker-compose.prod.yml</code> updated with a Postgres service variant</li><li>All migrations run cleanly against Postgres</li><li>End-to-end smoke test: login, console access, plugin enable/disable — all working on Postgres</li><li><code>docs/self-hosting.md</code> updated with Postgres configuration section</li></ul><p><strong>SRS reference:</strong> NFR-03, 3.7 Database Layer</p><p><strong>Review checklist:</strong></p><ul><li>Switching <code>DB_DIALECT=postgres</code> and <code>DATABASE_URL</code> is the only change required</li><li>No SQLite-specific queries anywhere in application code</li><li>Migrations apply cleanly to a fresh Postgres instance</li></ul><hr><h4 id="✅-0-9-—-ci-pipeline" tabindex="-1">✅ 0.9 — CI pipeline <a class="header-anchor" href="#✅-0-9-—-ci-pipeline" aria-label="Permalink to &quot;✅ 0.9 — CI pipeline&quot;">​</a></h4><p><strong>Goal:</strong> GitHub Actions pipelines for continuous validation and npm publishing.</p><p><strong>Deliverables:</strong></p><ul><li><code>.github/workflows/ci.yml</code> — validation, triggers on push to <code>main</code> and all pull requests: <ul><li><code>format</code> — runs <code>prettier --check .</code> across the repo; fails on any unformatted file</li><li><code>lint</code> — runs ESLint across all packages including the SDK import boundary rule (NFR-06)</li><li><code>typecheck</code> — runs <code>tsc --noEmit</code> across all packages</li><li><code>generate-validate</code> — runs <code>pnpm generate --mode=prod</code> and verifies <code>runtime/generated/registry.ts</code> is valid TypeScript</li><li><code>build</code> — runs <code>turbo build</code> in production mode</li><li>All jobs use pnpm cache for speed</li></ul></li><li><code>.github/workflows/publish.yml</code> — npm publishing, <strong>separate workflow</strong> triggered on per-package version tags (the two packages have independent release cycles): <ul><li>Tag pattern <code>sdk-v*.*.*</code> → builds and publishes <code>@sovereignfs/sdk</code></li><li>Tag pattern <code>ui-v*.*.*</code> → builds and publishes <code>@sovereignfs/ui</code></li><li>Steps: <code>pnpm install</code> → <code>pnpm --filter &lt;pkg&gt; build</code> (tsup → <code>dist/</code>) → <code>pnpm --filter &lt;pkg&gt; publish --no-git-checks --access public</code> using the <code>NODE_AUTH_TOKEN</code> repository secret</li><li>No other packages are ever published (internal <code>@sovereignfs/*</code> packages are <code>private</code> and workspace-only)</li><li>Publish runs only after the validation jobs pass on the tagged commit</li></ul></li></ul><p><strong>SRS reference:</strong> SRS 3.9 (CI validation step), PLT-07, NFR-06, NFR-04</p><p><strong>Review checklist:</strong></p><ul><li>All five validation jobs pass on a clean checkout</li><li>Unformatted file causes <code>format</code> job to fail</li><li>Import boundary violation in a plugin causes <code>lint</code> job to fail</li><li>Invalid manifest in <code>plugins/</code> causes <code>generate-validate</code> job to fail</li><li>pnpm cache is correctly restored between runs</li><li>Pushing an <code>sdk-v*</code> tag publishes only <code>@sovereignfs/sdk</code>; pushing a <code>ui-v*</code> tag publishes only <code>@sovereignfs/ui</code></li><li>A tag without a corresponding version bump in the package&#39;s <code>package.json</code> fails the publish (version already exists on npm)</li></ul><hr><h4 id="✅-0-10-—-deployment-upgrade-strategy" tabindex="-1">✅ 0.10 — Deployment &amp; upgrade strategy <a class="header-anchor" href="#✅-0-10-—-deployment-upgrade-strategy" aria-label="Permalink to &quot;✅ 0.10 — Deployment &amp; upgrade strategy&quot;">​</a></h4><blockquote><p>Full entry: <strong>[8.1]</strong> in <a href="./data-sovereignty.html">data-sovereignty.md</a> — Deployment &amp; upgrade strategy. This task also establishes the drizzle-kit migration runner and <code>sv backup</code>/<code>restore</code> commands referenced in this epic.</p></blockquote><hr><h4 id="✅-0-11-—-non-docker-production-deployment-phase-1-—-pm2" tabindex="-1">✅ 0.11 — Non-Docker production deployment, Phase 1 — PM2 <a class="header-anchor" href="#✅-0-11-—-non-docker-production-deployment-phase-1-—-pm2" aria-label="Permalink to &quot;✅ 0.11 — Non-Docker production deployment, Phase 1 — PM2&quot;">​</a></h4><p><strong>Goal:</strong> Ship the PM2 deployment path as the first-class non-Docker fallback (RFC 0026 Phase 1). Operators who can&#39;t or won&#39;t use Docker get a documented, supported path to production.</p><p><strong>Deliverables:</strong></p><ul><li><code>bin/sv.ts</code>: health-gate in <code>sv serve</code> — poll auth <code>GET /api/health</code> (<code>http://127.0.0.1:3001</code> by default, derived from <code>SOVEREIGN_AUTH_URL</code>) with a 30-second timeout before spawning the runtime process; log the wait via <code>consola.info</code>; exit non-zero with a clear error on timeout; unit-tested in <code>bin/__tests__/</code></li><li><code>bin/sv.ts</code>: new <code>sv setup pm2 [--dir &lt;install-dir&gt;] [--env-file &lt;path&gt;]</code> sub-command; template-fill logic in <code>bin/helpers.ts</code>; unit-tested</li><li><code>docs/examples/pm2.example.config.js</code> — canonical PM2 ecosystem config (same output as <code>sv setup pm2</code> with default arguments)</li><li><code>docs/self-hosting.md</code>: new &quot;Non-Docker deployment (PM2)&quot; section covering Node.js version requirement, build steps, <code>pm2 startup</code>/<code>pm2 save</code> for boot persistence, env-var differences table (Docker vs non-Docker), data-directory setup, upgrade procedure, and reverse-proxy references (reuse existing snippets)</li><li>SRS §3.1: PM2 added as a supported non-Docker deployment model</li></ul><p><strong>Dependencies:</strong> <code>sv serve</code> exists (Task 0.5.04); <code>sv backup</code>/<code>restore</code> (Task 0.5.13) referenced in the upgrade procedure but not a hard blocker</p><p><strong>SRS reference:</strong> RFC 0026 Phase 1, SRS §3.1</p><p><strong>Review checklist:</strong></p><ul><li><code>sv serve</code> logs the health-gate wait and exits cleanly if auth never becomes healthy within 30 s; unit test covers the poll logic</li><li><code>sv setup pm2</code> produces a valid PM2 ecosystem config with correct paths, env, and <code>HOSTNAME=127.0.0.1</code> on the auth entry</li><li><code>docs/self-hosting.md</code> PM2 section is self-contained: a reader with Node.js, pnpm, and PM2 installed can follow it to a running instance without Docker</li></ul><hr><h4 id="✅-0-12-—-e2e-golden-path-test-suite" tabindex="-1">✅ 0.12 — E2E golden-path test suite <a class="header-anchor" href="#✅-0-12-—-e2e-golden-path-test-suite" aria-label="Permalink to &quot;✅ 0.12 — E2E golden-path test suite&quot;">​</a></h4><p><strong>Goal:</strong> Wire up Playwright as the browser-automation layer and write 20 golden-path tests covering the critical user flows: auth (login/logout/redirect), launcher navigation, Account and Console plugin pages, platform shell navigation (root rewrite, brand link, avatar menu), and the monetization paywall flow.</p><p><strong>Scope:</strong></p><ul><li><code>playwright.config.ts</code> — config with dual <code>webServer</code> (auth <code>:3001</code>, runtime <code>:3000</code>), <code>globalSetup</code>, chromium-only in CI, <code>retries: 1</code> to absorb Next.js lazy-compilation 404s</li><li><code>__tests__/e2e/global-setup.ts</code> — seeds test users via <code>pnpm sv seed</code>, saves storage state for both users, generates test Ed25519 keypair for paywall spec</li><li><code>__tests__/e2e/fixtures.ts</code> — <code>adminPage</code> / <code>userPage</code> fixture helpers</li><li>Six spec files (20 tests total): <code>auth</code>, <code>launcher</code>, <code>account</code>, <code>console</code>, <code>navigation</code>, <code>paywall</code></li><li><code>.github/workflows/e2e.yml</code> — CI job, triggers on <code>push: main</code> with <code>paths</code> filter (source only, not docs/md)</li><li><code>docs/testing-e2e.md</code> — local run guide + full coverage/deferred-flow table</li></ul><p><strong>Version bumps:</strong> none (devDependency only — <code>@playwright/test</code>; no package API changes).</p><p><strong>SRS reference:</strong> RFC 0010 (test organisation); SRS NFR-11 (accessibility/quality).</p><p><strong>Review checklist:</strong></p><ul><li><code>pnpm test:e2e</code> passes all 20 tests locally against <code>pnpm dev</code> servers</li><li><code>pnpm test</code> (Vitest) still passes unchanged (no <code>.spec.ts</code> picked up)</li><li><code>pnpm lint</code> passes (<code>__tests__/e2e/**</code> and <code>playwright.config.ts</code> excluded from ESLint)</li><li><code>e2e.yml</code> workflow appears in GitHub Actions after merge; passes on next source-code push to main</li></ul><hr><h4 id="📋-0-13-—-non-docker-production-deployment-phase-2-—-systemd" tabindex="-1">📋 0.13 — Non-Docker production deployment, Phase 2 — systemd <a class="header-anchor" href="#📋-0-13-—-non-docker-production-deployment-phase-2-—-systemd" aria-label="Permalink to &quot;📋 0.13 — Non-Docker production deployment, Phase 2 — systemd&quot;">​</a></h4><p><strong>Goal:</strong> Add systemd as a zero-extra-dependency alternative to PM2 for Linux server operators (RFC 0026 Phase 2). Phase 1 (PM2) must ship first.</p><p><strong>Deliverables:</strong></p><ul><li><code>bin/sv.ts</code>: <code>sv setup systemd [--user &lt;user&gt;] [--dir &lt;dir&gt;] [--env-file &lt;path&gt;]</code> sub-command writing two pre-filled unit files to the current directory; template logic in <code>bin/helpers.ts</code>; unit-tested</li><li><code>docs/examples/sovereign-auth.service</code>, <code>docs/examples/sovereign-runtime.service</code> — canonical unit files (same as <code>sv setup systemd</code> defaults): <code>User=sovereign</code>, <code>WorkingDirectory=</code>, <code>EnvironmentFile=</code>, <code>HOSTNAME=127.0.0.1</code> on auth, <code>ExecStartPre</code> health-poll on the runtime unit, <code>Restart=on-failure</code></li><li><code>docs/self-hosting.md</code>: &quot;Non-Docker deployment (systemd)&quot; section alongside the PM2 section; covers account creation, <code>EnvironmentFile</code> setup, <code>systemctl enable</code>, log access via <code>journalctl</code>, and the upgrade procedure</li><li>Document <code>sv serve</code> as a valid single-process target under either PM2 or systemd (simplest path for minimal init systems)</li><li>SRS §3.1: systemd noted as the recommended Linux-native alternative to PM2</li></ul><p><strong>Dependencies:</strong> Task 0.5.29 (Phase 1 — PM2 and <code>sv serve</code> health-gate must be in place)</p><p><strong>SRS reference:</strong> RFC 0026 Phase 2, SRS §3.1</p><p><strong>Review checklist:</strong></p><ul><li><code>sv setup systemd</code> produces two syntactically valid unit files with correct <code>WorkingDirectory</code>, <code>EnvironmentFile</code>, <code>HOSTNAME</code>, and <code>ExecStartPre</code> health-poll</li><li><code>systemctl start sovereign-runtime</code> waits for <code>sovereign-auth</code> to pass its health check before the runtime process starts</li><li><code>docs/self-hosting.md</code> systemd section is self-contained alongside the PM2 section</li></ul><hr><h2 id="related-rfcs" tabindex="-1">Related RFCs <a class="header-anchor" href="#related-rfcs" aria-label="Permalink to &quot;Related RFCs&quot;">​</a></h2><ul><li><a href="./../rfcs/0006-deployment-upgrade-strategy.html">RFC 0006 — Deployment &amp; upgrade strategy</a></li><li><a href="./../rfcs/0010-test-organization.html">RFC 0010 — Test organization</a></li><li><a href="./../rfcs/0019-test-setup-and-seeding.html">RFC 0019 — Test setup &amp; seeding</a></li><li><a href="./../rfcs/0026-non-docker-deployment.html">RFC 0026 — Non-Docker deployment</a></li></ul><h2 id="related-docs" tabindex="-1">Related Docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related Docs&quot;">​</a></h2><ul><li><a href="./../self-hosting.html">self-hosting.md</a></li><li><a href="./../testing-e2e.html">testing-e2e.md</a></li><li><a href="./../upgrade.html">upgrade.md — runtime version map + v1.0.0 checklist</a></li><li><a href="./../upgrade.html">upgrade.md</a></li></ul>',114)])])}const g=o(s,[["render",d]]);export{h as __pageData,g as default};
